#include <stdio.h>
int main() {
    int N, M;
    scanf("%d", &N);
    int arr[N];
    for (int i = 0; i < N; i++) {
        scanf("%d", &arr[i]);
    }
    scanf("%d", &M);
    for (int i = 0; i < M; i++) {
        int type, l, r, p, d;
        scanf("%d %d %d", &type, &l, &r);
        if (type == 1) {
            scanf("%d", &p);
            for (int j = l - 1; j < r; j++) {
                if (arr[j] % p == 0) {
                    arr[j] /= p;
                }
            }
        } else {
            scanf("%d", &d);
            arr[l - 1] = d;
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", arr[i]);
    }
    return 0;
}

